#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N;
        scanf("%lld", &N);
        if (N % 3 != 0) {
            printf("-1\n");
        } else {
            long long x = N / 3;
            printf("%lld %lld %lld\n", x, x, x);
        }
    }
    return 0;
}

